        use crate::collections::bounded_vec::BoundedVec;

        // map in terms of for_each
        fn for_each_map<T, U, Env, let MaxLen: u32>(
            input: BoundedVec<T, MaxLen>,
            f: fn[Env](T) -> U,
        ) -> BoundedVec<U, MaxLen> {
            let mut output = BoundedVec::<U, MaxLen>::new();
